import{_ as t,o,c as i,aw as a}from"./chunks/framework.DLufY-ao.js";const h=JSON.parse('{"title":"Spec-Driven Development (SDD)","description":"","frontmatter":{},"headers":[],"relativePath":"wiki/dev-commit/theory/methodology-dev/principles/sdd.md","filePath":"wiki/dev-commit/theory/methodology-dev/principles/sdd.md"}'),l={name:"wiki/dev-commit/theory/methodology-dev/principles/sdd.md"};function r(n,e,s,d,c,p){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="spec-driven-development-sdd" tabindex="-1">Spec-Driven Development (SDD) <a class="header-anchor" href="#spec-driven-development-sdd" aria-label="Permalink to &quot;Spec-Driven Development (SDD)&quot;">​</a></h1><h2 id="информация" tabindex="-1">Информация <a class="header-anchor" href="#информация" aria-label="Permalink to &quot;Информация&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Spec-Driven Development</p><ul><li><strong>Spec-Driven Development (SDD)</strong> - это подход, когда вначале описывается спецификация, а потом LLM генерирует код на основе этой спецификации.</li><li>Методология разработки программного обеспечения, при которой спецификации становятся источником истины вместо кода. Перед написанием реализации команда (или ассистент на базе ИИ) определяет, что должно делать система: требования, ожидаемое поведение, ограничения, критерии приёмки.</li><li>В отличие от подходов «код сначала», где реализация предшествует документации, SDD требует, чтобы детальные спецификации (например, контракты API, планы архитектуры, критерии приёмки) создавались, проверялись и утверждались перед написанием первой строки производственного кода.</li></ul></div><h2 id="принципы" tabindex="-1">Принципы <a class="header-anchor" href="#принципы" aria-label="Permalink to &quot;Принципы&quot;">​</a></h2><ul><li><strong>Детализированные спецификации</strong>. В документе Software Design (SDD) описываются, что должно делать программное обеспечение, включая ожидаемые функции и важные факторы (безопасность, производительность). Часто используются визуальные средства и примеры, чтобы прояснить, как всё должно работать.</li><li><strong>Ранний обзор</strong>. Перед началом кодирования спецификации проверяют члены команды, тестировщики и иногда автоматические инструменты, чтобы выявить и исправить потенциальные проблемы.</li><li><strong>Автоматизированная разработка</strong>. Разработчики используют специальные инструменты, которые помогают превращать детальные планы непосредственно в рабочий код.</li><li><strong>Постоянная поддержка</strong>. После запуска программного обеспечения спецификации остаются полезным ориентиром для будущего сопровождения и обновлений.</li></ul><h2 id="структура" tabindex="-1">Структура <a class="header-anchor" href="#структура" aria-label="Permalink to &quot;Структура&quot;">​</a></h2><blockquote><p>Идея → Спецификация → План реализации → Декомпозиция задач → Код → Проверки</p></blockquote>',7)])])}const D=t(l,[["render",r]]);export{h as __pageData,D as default};
